import { Router } from "express";
import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/productService.js";
import { ServiceError, mapErrorToStatus } from "../errors.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const parsedCategory =
    typeof category === "string" ? category : undefined;
  const parsedMinPrice =
    typeof minPrice === "string" ? parseFloat(minPrice) : undefined;
  const parsedMaxPrice =
    typeof maxPrice === "string" ? parseFloat(maxPrice) : undefined;

  const result = listProducts({
    category: parsedCategory,
    minPrice:
      parsedMinPrice !== undefined && !isNaN(parsedMinPrice)
        ? parsedMinPrice
        : undefined,
    maxPrice:
      parsedMaxPrice !== undefined && !isNaN(parsedMaxPrice)
        ? parsedMaxPrice
        : undefined,
  });

  res.json(result);
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const product = getProductById(id);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(mapErrorToStatus(err.code)).json({ error: err.message });
      return;
    }
    res.status(500).json({ error: "Internal server error" });
  }
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: unknown };
    const product = adjustProductStock(id, adjustment);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(mapErrorToStatus(err.code)).json({ error: err.message });
      return;
    }
    res.status(500).json({ error: "Internal server error" });
  }
});

export { router as productRouter };

